import{_ as e,c as a,o as s,d as i}from"./app.6c679333.js";const f='{"title":"Autenticaci\xF3n - Vue SPA","description":"","frontmatter":{},"headers":[{"level":2,"title":"Puntos finales de autenticaci\xF3n y CORS","slug":"puntos-finales-de-autenticacion-y-cors"},{"level":2,"title":"Sesiones, Cookies y CSRF","slug":"sesiones-cookies-y-csrf"}],"relativePath":"vue/vue-authentication.md"}',n={},t=i(`<h1 id="autenticacion-vue-spa" tabindex="-1">Autenticaci\xF3n - Vue SPA <a class="header-anchor" href="#autenticacion-vue-spa" aria-hidden="true">#</a></h1><h2 id="puntos-finales-de-autenticacion-y-cors" tabindex="-1">Puntos finales de autenticaci\xF3n y CORS <a class="header-anchor" href="#puntos-finales-de-autenticacion-y-cors" aria-hidden="true">#</a></h2><p>El archivo <a href="https://github.com/CaribesTIC/vue-frontend-ts/blob/main/src/modules/Auth/services/index.ts" target="_blank" rel="noopener noreferrer">src/modules/Auth/services/index.ts</a> mantiene todos los puntos finales de autenticaci\xF3n de API en un solo lugar. Los m\xE9todos en este archivo interact\xFAan con los puntos finales de Fortify que hemos configurado previamente.</p><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Es importante resaltar que esto requiere que el SPA y la API compartan el mismo dominio de nivel superior. Sin embargo, pueden colocarse en diferentes subdominios.</p></div><h2 id="sesiones-cookies-y-csrf" tabindex="-1">Sesiones, Cookies y CSRF <a class="header-anchor" href="#sesiones-cookies-y-csrf" aria-hidden="true">#</a></h2><p>Para autenticar nuestra SPA, la p\xE1gina de inicio de sesi\xF3n primero debe realizar una solicitud al extremo <code>/sanctum/csrf-cookie</code> para inicializar la protecci\xF3n CSRF para la aplicaci\xF3n:</p><div class="language-ts"><pre><code><span class="token keyword">await</span> Http<span class="token punctuation">.</span><span class="token function">get</span><span class="token punctuation">(</span><span class="token string">&quot;/sanctum/csrf-cookie&quot;</span><span class="token punctuation">)</span><span class="token punctuation">;</span>
</code></pre></div><p>Esto tambi\xE9n se aplica a cualquier otra acci\xF3n de Fortify que requiera protecci\xF3n CSRF. T\xE9ngase en cuenta otras rutas en dicho m\xF3dulo que tambi\xE9n incluyen una solicitud de obtenci\xF3n de la cookie CSRF; <code>forgotPassword</code>, <code>resetPassword</code>, etc.</p><p>Si una solicitud de inicio de sesi\xF3n tiene \xE9xito, el usuario se autentica y las solicitudes posteriores al SPA se autenticar\xE1n autom\xE1ticamente a trav\xE9s de la cookie de sesi\xF3n que emite la aplicaci\xF3n Laravel. Adem\xE1s, dado que ya hicimos una solicitud a la ruta <code>/sanctum/csrf-cookie</code>, las solicitudes posteriores deber\xEDan recibir autom\xE1ticamente protecci\xF3n CSRF porque Axios env\xEDa autom\xE1ticamente la cookie XSRF-TOKEN en el encabezado X-XSRF-TOKEN.</p>`,9),o=[t];function c(r,u,d,l,p,m){return s(),a("div",null,o)}var _=e(n,[["render",c]]);export{f as __pageData,_ as default};
